import type { IPDFTemplate, AggregatedOrder } from '../types';

// 格式化日期为 YYYY-MM-DD
function formatDate(date: Date): string {
  const year = date.getFullYear();
  const month = String(date.getMonth() + 1).padStart(2, '0');
  const day = String(date.getDate()).padStart(2, '0');
  return `${year}-${month}-${day}`;
}

// Logo base64 data
const LOGO_BASE64 = 'data:image/png;base64,';

function generateInvoiceHTML(
  data: AggregatedOrder,
  editedValues?: Record<string, string>,
  invoiceNumber?: string
): string {
  // 通过字段名获取值（优先使用编辑后的值）
  const getValueByField = (fieldName: string): string => {
    // 首先检查编辑值中的标准key
    if (editedValues) {
      // 检查标准化的key
      const fn = fieldName.toLowerCase().replace(/\s+/g, '');
      if (fn === 'ponumber' && editedValues['poNumber'] !== undefined) return editedValues['poNumber'];
      if (fn === 'shippingmethod' && editedValues['shippingMethod'] !== undefined) return editedValues['shippingMethod'];
      if (fn === 'firm' && editedValues['firm'] !== undefined) return editedValues['firm'];
      if (fn === 'billto' && editedValues['billTo'] !== undefined) return editedValues['billTo'];
      if (fn === 'shipto' && editedValues['shipTo'] !== undefined) return editedValues['shipTo'];
      // 检查原始字段名
      if (editedValues[fieldName] !== undefined) return editedValues[fieldName];
    }
    const header = data.header as Record<string, string>;
    const fn = fieldName.toLowerCase().replace(/\s+/g, '');
    for (const [k, v] of Object.entries(header)) {
      if (k.toLowerCase().replace(/\s+/g, '') === fn) return v;
    }
    if (fn === 'subtotal') return data.subtotal || '';
    if (fn === 'shippingcost' || fn === 'shipping') return data.shippingCost || '';
    if (fn === 'total') return data.total || '';
    return '';
  };

  // 固定字段
  const companyName = 'APROMO GIFT CORPORATION';
  const companyAddress = '99 Wall Street #179\nNew York, 10005\nUnited States';
  const finalInvoiceNumber = invoiceNumber || 'AG-001';
  const invoiceDate = formatDate(new Date());
  const poNumber = getValueByField('PO number');
  const inHandDate = getValueByField('In-hand Date');
  const firm = getValueByField('Firm');
  const billTo = getValueByField('Bill to');
  const shipTo = getValueByField('Ship to');
  const shippingMethod = getValueByField('Shipping method');
  const subtotal = getValueByField('Subtotal');
  const shippingCost = getValueByField('Shipping Cost');
  const total = getValueByField('Total');

  // 固定的 Comments 备注
  const comments = `Due to the current economic circumstances in today's Shipping industry, we cannot guarantee their regular times of delivery. We will do our best to have every order arrive on time, within the Shipping window, but cannot guarantee there will not be delays based upon the company or Shipping/delivery address selected. Thank you for your understanding in this matter, as it is without our control.
All fees are listed in USD and are subject to sales tax (as applicable).`;

  // 生成商品行 HTML（多行聚合）
  // 格式化商品名：只加粗第一行，保留换行
  const formatProduct = (product: string): string => {
    if (!product) return '';
    const lines = product.split('\n');
    if (lines.length === 1) {
      return `<div style="font-weight: bold; margin-bottom: 5px; color: #000; font-size: 9pt;">${product}</div>`;
    }
    // 多行：第一行加粗，其他行不加粗
    const firstLine = lines[0];
    const otherLines = lines.slice(1);
    let html = `<div style="font-weight: bold; margin-bottom: 5px; color: #000; font-size: 9pt;">${firstLine}</div>`;
    if (otherLines.length > 0) {
      html += `<div style="font-size: 9pt; color: #000; line-height: 1.5;">${otherLines.join('<br/>')}</div>`;
    }
    return html;
  };

  const itemRows = data.items.map((item) => `
            <tr>
              <td style="padding: 12px; border-bottom: 1px solid #ccc; border-left: 1px solid #ccc; vertical-align: top;">
                ${formatProduct(item.product || '')}
                ${item.description ? `<div style="font-size: 8pt; color: #555; line-height: 1.5; margin-top: 3px;">${item.description}</div>` : ''}
              </td>
              <td style="padding: 12px 8px; border-bottom: 1px solid #ccc; border-left: 1px solid #ccc; border-right: 1px solid #ccc; text-align: center; vertical-align: top;">${item.qty || ''}</td>
              <td style="padding: 12px 8px; border-bottom: 1px solid #ccc; border-left: 1px solid #ccc; border-right: 1px solid #ccc; text-align: right; vertical-align: top;">${item.unitPrice || ''}</td>
              <td style="padding: 12px; border-bottom: 1px solid #ccc; border-left: 1px solid #ccc; border-right: 1px solid #ccc; text-align: right; vertical-align: top; font-weight: bold;">${item.amount || ''}</td>
            </tr>`).join('');

  // Setup Charge 行（如果存在）
  const setupCharge = getValueByField('Setup Charge');
  const setupQty = getValueByField('Setup QTY');
  const amount2 = getValueByField('AMOUNT 2');
  const setupChargeRow = setupCharge ? `
            <tr>
              <td style="padding: 12px; border-bottom: 1px solid #ccc; border-left: 1px solid #ccc; color: #333; font-size: 9pt;">Set up Charge</td>
              <td style="padding: 12px 8px; border-bottom: 1px solid #ccc; border-left: 1px solid #ccc; border-right: 1px solid #ccc; text-align: center; vertical-align: top;">${setupQty}</td>
              <td style="padding: 12px 8px; border-bottom: 1px solid #ccc; border-left: 1px solid #ccc; border-right: 1px solid #ccc; text-align: right; vertical-align: top;">${setupCharge}</td>
              <td style="padding: 12px; border-bottom: 1px solid #ccc; border-left: 1px solid #ccc; border-right: 1px solid #ccc; text-align: right; font-weight: bold;">${amount2}</td>
            </tr>` : '';

  return `
      <div style="font-family: Georgia, 'Times New Roman', Times, serif; padding: 40px 35px; width: 100%; max-width: 100%; margin: 0 auto; color: #000; font-size: 11pt; line-height: 1.6; box-sizing: border-box;">
        <!-- Header: Logo + Company Info + INVOICE Title -->
        <table style="width: 100%; margin-bottom: 20px;">
          <tr>
            <td style="vertical-align: top; width: 55%; padding-right: 15px;">
              <div style="margin-bottom: 12px;">
                <img src="${LOGO_BASE64}" alt="Logo" style="height: 60px; width: auto; margin-bottom: 8px;" />
              </div>
              <div style="font-size: 12pt; font-weight: bold; color: #000; margin-bottom: 8px;">${companyName}</div>
              <div style="font-size: 9pt; color: #333; line-height: 1.7; white-space: pre-line;">${companyAddress}</div>
            </td>
            <td style="vertical-align: top; text-align: right; width: 45%; padding-left: 15px;">
              <div style="font-size: 24pt; font-weight: bold; color: #000; margin-bottom: 12px; letter-spacing: 2px;">INVOICE</div>
              <table style="font-size: 9pt; margin-left: auto;">
                <tr>
                  <td style="text-align: right; padding: 4px 10px 4px 0; color: #555; white-space: nowrap;">Invoice number:</td>
                  <td style="text-align: left; padding: 4px 0; font-weight: bold; color: #000;">${finalInvoiceNumber}</td>
                </tr>
                <tr>
                  <td style="text-align: right; padding: 4px 10px 4px 0; color: #555; white-space: nowrap;">Invoice date:</td>
                  <td style="text-align: left; padding: 4px 0; font-weight: bold; color: #000;">${invoiceDate}</td>
                </tr>
                <tr>
                  <td style="text-align: right; padding: 4px 10px 4px 0; color: #555; white-space: nowrap;">PO number:</td>
                  <td style="text-align: left; padding: 4px 0; font-weight: bold; color: #000;">${poNumber}</td>
                </tr>
                <tr>
                  <td style="text-align: right; padding: 4px 10px 4px 0; color: #555; white-space: nowrap;">In-hand Date:</td>
                  <td style="text-align: left; padding: 4px 0; font-weight: bold; color: #000;">${inHandDate}</td>
                </tr>
                <tr>
                  <td style="text-align: right; padding: 4px 10px 4px 0; color: #555; white-space: nowrap;">Firm:</td>
                  <td style="text-align: left; padding: 4px 0; font-weight: bold; color: #000;">${firm}</td>
                </tr>
              </table>
            </td>
          </tr>
        </table>

        <!-- Divider Line -->
        <hr style="border: none; border-top: 2px solid #000; margin: 20px 0 25px 0;" />

        <!-- Bill to / Ship to / Shipping method -->
        <table style="width: 100%; margin-bottom: 30px;">
          <tr>
            <td style="vertical-align: top; width: 50%; padding-right: 20px;">
              <div style="font-weight: bold; margin-bottom: 8px; color: #000; font-size: 9pt; text-transform: uppercase; letter-spacing: 1px; border-bottom: 1px solid #ccc; padding-bottom: 4px;">Bill to:</div>
              <div style="font-size: 9pt; color: #333; line-height: 1.7; white-space: pre-line; padding-top: 6px;">${billTo}</div>
            </td>
            <td style="vertical-align: top; width: 50%; padding-left: 20px;">
              <div style="font-weight: bold; margin-bottom: 8px; color: #000; font-size: 9pt; text-transform: uppercase; letter-spacing: 1px; border-bottom: 1px solid #ccc; padding-bottom: 4px;">Ship to:</div>
              <div style="font-size: 9pt; color: #333; line-height: 1.7; white-space: pre-line; padding-top: 6px;">${shipTo}</div>
              ${shippingMethod ? `<div style="font-weight: bold; margin-top: 15px; margin-bottom: 6px; color: #000; font-size: 9pt; text-transform: uppercase; letter-spacing: 1px; border-bottom: 1px solid #ccc; padding-bottom: 4px;">Shipping method:</div>
              <div style="font-size: 9pt; color: #333; line-height: 1.7; padding-top: 6px;">${shippingMethod}</div>` : ''}
            </td>
          </tr>
        </table>

        <!-- Total Display (Prominent) -->
        <div style="margin-bottom: 25px; text-align: right;">
          <table style="margin-left: auto;">
            <tr>
              <td style="padding: 0 15px 0 0; color: #555; font-size: 9pt; vertical-align: middle;">Total:</td>
              <td style="font-size: 18pt; font-weight: bold; color: #000;">${total}</td>
            </tr>
          </table>
        </div>

        <!-- Products Table -->
        <table style="width: 100%; border-collapse: collapse; margin-bottom: 20px; font-size: 9pt;">
          <thead>
            <tr style="background-color: #f5f5f5;">
              <th style="padding: 10px 12px; border-top: 2px solid #000; border-bottom: 2px solid #000; border-left: 1px solid #ccc; text-align: left; font-weight: bold; color: #000; text-transform: uppercase; font-size: 8pt; letter-spacing: 1px;">PRODUCTS & SERVICES</th>
              <th style="padding: 10px 8px; border-top: 2px solid #000; border-bottom: 2px solid #000; border-left: 1px solid #ccc; border-right: 1px solid #ccc; text-align: center; font-weight: bold; color: #000; width: 50pt; text-transform: uppercase; font-size: 8pt; letter-spacing: 1px;">QTY</th>
              <th style="padding: 10px 8px; border-top: 2px solid #000; border-bottom: 2px solid #000; border-left: 1px solid #ccc; border-right: 1px solid #ccc; text-align: right; font-weight: bold; color: #000; width: 70pt; text-transform: uppercase; font-size: 8pt; letter-spacing: 1px;">UNIT PRICE</th>
              <th style="padding: 10px 12px; border-top: 2px solid #000; border-bottom: 2px solid #000; border-left: 1px solid #ccc; border-right: 1px solid #ccc; text-align: right; font-weight: bold; color: #000; width: 80pt; text-transform: uppercase; font-size: 8pt; letter-spacing: 1px;">AMOUNT</th>
            </tr>
          </thead>
          <tbody>
            ${itemRows}
            ${setupChargeRow}
          </tbody>
        </table>

        <!-- Divider Line -->
        <hr style="border: none; border-top: 1px solid #ccc; margin: 20px 0;" />

        <!-- Amount Summary -->
        <div style="text-align: right; margin-bottom: 30px;">
          <table style="margin-left: auto; font-size: 9pt;">
            <tr>
              <td style="padding: 6px 20px 6px 0; color: #555; text-align: right;">Subtotal:</td>
              <td style="padding: 6px 0; text-align: right; width: 80pt; font-weight: bold;">${subtotal}</td>
            </tr>
            ${shippingCost ? `<tr>
              <td style="padding: 6px 20px 6px 0; color: #555; text-align: right;">Shipping:</td>
              <td style="padding: 6px 0; text-align: right; font-weight: bold;">${shippingCost}</td>
            </tr>` : ''}
            <tr style="font-weight: bold; font-size: 10pt;">
              <td style="padding: 10px 20px 10px 0; color: #000; border-top: 2px solid #000; text-align: right;">Total:</td>
              <td style="padding: 10px 0; text-align: right; border-top: 2px solid #000;">${total}</td>
            </tr>
          </table>
        </div>

        <!-- Comments -->
        <div style="margin-top: auto; padding-top: 25px; border-top: 2px solid #000;">
          <div style="font-weight: bold; margin-bottom: 10px; color: #000; font-size: 9pt; text-transform: uppercase; letter-spacing: 1px;">Comments:</div>
          <div style="font-size: 8pt; color: #444; line-height: 1.7; white-space: pre-line;">${comments}</div>
        </div>
      </div>
    `;
}

// 导出 Invoice 模板对象
export const InvoiceTemplate: IPDFTemplate = {
  id: 'invoice',
  name: 'Invoice',
  description: '发票模板，包含公司信息、账单明细等',
  fields: {
    required: ['PO number', 'Bill to', 'Ship to', 'PRODUCTS', 'QTY', 'UNIT PRICE', 'Amount', 'Subtotal', 'Total'],
    optional: ['In-hand Date', 'Firm', 'Shipping method', 'Description(颜色/印刷等)', 'Setup QTY', 'Setup Charge', 'AMOUNT 2', 'Shipping Cost'],
    editable: ['PO number', 'Bill to', 'Ship to', 'Shipping method', 'Firm'],
    amountFields: ['Subtotal', 'Total', 'Amount', 'AMOUNT 2', 'Shipping Cost', 'UNIT PRICE', 'Setup Charge'],
  },
  generate(data: AggregatedOrder, editedValues?: Record<string, string>, invoiceNumber?: string): string {
    return generateInvoiceHTML(data, editedValues, invoiceNumber);
  },
};

// 额外导出生成函数
export { generateInvoiceHTML };
